module JC_counter(
    input clk, input rst_n,
    output reg [63:0] Q
);
    integer i;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            Q <= 64'b0;
        end else begin
            if (Q[0] == 1'b0) begin
                Q <= {1'b1, Q[63:1]};
            end else begin
                Q <= {1'b0, Q[63:1]};
            end
        end
    end
endmodule
